})

// ── /api/auth/verify ────────────────────────────────────────

describe('/api/auth/verify', () => {
  it('valid token + purchase in KV → 302 redirect with Set-Cookie', async () => {
    const kv = new Map<string, string>()
    const purchase: PurchaseRecord = {
      sessionId: 'sess_original',
      email: 'buyer@example.com',
      bookSlug: 'test-book',
      amount: 999,
